import React, { Component } from 'react';
import './App.css';
import Header from './components/Header';
import Song from './components/Song';

class App extends Component {
  // Datos ficticios de canciones (temática Apple Music)
  songs = [
    {
      id: 1,
      title: "Blinding Lights",
      artist: "The Weeknd",
      duration: "3:20",
      albumCover: "https://upload.wikimedia.org/wikipedia/en/9/9d/The_Weeknd_-_Blinding_Lights.png"
    },
    {
      id: 2,
      title: "Levitating",
      artist: "Dua Lipa",
      duration: "3:23",
      albumCover: "https://upload.wikimedia.org/wikipedia/en/5/54/Dua_Lipa_-_Levitating.png"
    },
    {
      id: 3,
      title: "Save Your Tears",
      artist: "The Weeknd",
      duration: "3:35",
      albumCover: "https://upload.wikimedia.org/wikipedia/en/5/5a/The_Weeknd_-_Save_Your_Tears.png"
    },
    {
      id: 4,
      title: "Don't Start Now",
      artist: "Dua Lipa",
      duration: "3:03",
      albumCover: "https://upload.wikimedia.org/wikipedia/en/3/3a/Dua_Lipa_-_Don%27t_Start_Now.png"
    },
    {
      id: 5,
      title: "Shape of You",
      artist: "Ed Sheeran",
      duration: "3:53",
      albumCover: "https://upload.wikimedia.org/wikipedia/en/4/45/Shape_of_You.png"
    }
  ];

  componentDidMount() {
    console.log("🎵 App de Apple Music cargada correctamente");
  }

  render() {
    return (
      <div className="app">
        <Header />
        <main className="library">
          <h2 className="library__title">Biblioteca Musical</h2>
          <div className="songs-list">
            {this.songs.map(song => (
              <Song
                key={song.id}
                title={song.title}
                artist={song.artist}
                duration={song.duration}
                albumCover={song.albumCover}
              />
            ))}
          </div>
        </main>
      </div>
    );
  }
}

export default App;
